import{_ as e,o as a,c as t,aw as o}from"./chunks/framework.Dq2onT5h.js";const s=JSON.parse('{"title":"ev-abci Flags Reference","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ev-abci Flags Reference | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"reference/configuration/ev-abci-flags.md","filePath":"reference/configuration/ev-abci-flags.md","lastUpdated":1772446570000}');const n=e({name:"reference/configuration/ev-abci-flags.md"},[["render",function(e,s,n,d,r,l){return a(),t("div",null,[...s[0]||(s[0]=[o('<h1 id="ev-abci-flags-reference" tabindex="-1">ev-abci Flags Reference <a class="header-anchor" href="#ev-abci-flags-reference" aria-label="Permalink to &quot;ev-abci Flags Reference&quot;">​</a></h1><p>Command-line flags for Cosmos SDK applications using ev-abci.</p><h2 id="ev-node-flags" tabindex="-1">ev-node Flags <a class="header-anchor" href="#ev-node-flags" aria-label="Permalink to &quot;ev-node Flags&quot;">​</a></h2><p>These flags configure the underlying ev-node instance.</p><h3 id="node-configuration" tabindex="-1">Node Configuration <a class="header-anchor" href="#node-configuration" aria-label="Permalink to &quot;Node Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.node.aggregator</code></td><td>bool</td><td><code>false</code></td><td>Run as block producer</td></tr><tr><td><code>--evnode.node.block_time</code></td><td>duration</td><td><code>1s</code></td><td>Block production interval</td></tr><tr><td><code>--evnode.node.lazy_aggregator</code></td><td>bool</td><td><code>false</code></td><td>Only produce blocks with txs</td></tr><tr><td><code>--evnode.node.lazy_block_time</code></td><td>duration</td><td><code>1s</code></td><td>Max wait in lazy mode</td></tr></tbody></table><h3 id="da-configuration" tabindex="-1">DA Configuration <a class="header-anchor" href="#da-configuration" aria-label="Permalink to &quot;DA Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.da.address</code></td><td>string</td><td>required</td><td>DA layer URL</td></tr><tr><td><code>--evnode.da.auth_token</code></td><td>string</td><td><code>&quot;&quot;</code></td><td>DA authentication token</td></tr><tr><td><code>--evnode.da.namespace</code></td><td>string</td><td><code>&quot;&quot;</code></td><td>DA namespace (hex)</td></tr><tr><td><code>--evnode.da.gas_price</code></td><td>float</td><td><code>0.01</code></td><td>DA gas price</td></tr></tbody></table><h3 id="p2p-configuration" tabindex="-1">P2P Configuration <a class="header-anchor" href="#p2p-configuration" aria-label="Permalink to &quot;P2P Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.p2p.listen</code></td><td>string</td><td><code>/ip4/0.0.0.0/tcp/26656</code></td><td>P2P listen address</td></tr><tr><td><code>--evnode.p2p.peers</code></td><td>string</td><td><code>&quot;&quot;</code></td><td>Comma-separated peer addresses</td></tr><tr><td><code>--evnode.p2p.blocked</code></td><td>string</td><td><code>&quot;&quot;</code></td><td>Blocked peer IDs</td></tr></tbody></table><h3 id="signer-configuration" tabindex="-1">Signer Configuration <a class="header-anchor" href="#signer-configuration" aria-label="Permalink to &quot;Signer Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.signer.passphrase</code></td><td>string</td><td>required</td><td>Signer key passphrase</td></tr></tbody></table><h3 id="rpc-configuration" tabindex="-1">RPC Configuration <a class="header-anchor" href="#rpc-configuration" aria-label="Permalink to &quot;RPC Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.rpc.address</code></td><td>string</td><td><code>tcp://0.0.0.0:26657</code></td><td>RPC listen address</td></tr></tbody></table><h2 id="cosmos-sdk-flags" tabindex="-1">Cosmos SDK Flags <a class="header-anchor" href="#cosmos-sdk-flags" aria-label="Permalink to &quot;Cosmos SDK Flags&quot;">​</a></h2><p>Standard Cosmos SDK flags remain available:</p><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--home</code></td><td>Application home directory</td></tr><tr><td><code>--log_level</code></td><td>Log level (debug, info, warn, error)</td></tr><tr><td><code>--log_format</code></td><td>Log format (plain, json)</td></tr><tr><td><code>--trace</code></td><td>Enable full stack traces</td></tr></tbody></table><h2 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h2><p>Flags can be set via environment variables:</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#DBD7CA;">EVNODE_NODE_AGGREGATOR</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">true</span></span>\n<span class="line"><span style="color:#DBD7CA;">EVNODE_DA_ADDRESS</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">http://localhost:7980</span></span>\n<span class="line"><span style="color:#DBD7CA;">EVNODE_SIGNER_PASSPHRASE</span><span style="color:#767676;">=</span><span style="color:#BFF3C2;">secret</span></span></code></pre></div><p>Pattern: <code>EVNODE_&lt;SECTION&gt;_&lt;FLAG&gt;</code> (uppercase, underscores)</p><h2 id="examples" tabindex="-1">Examples <a class="header-anchor" href="#examples" aria-label="Permalink to &quot;Examples&quot;">​</a></h2><h3 id="sequencer-node" tabindex="-1">Sequencer Node <a class="header-anchor" href="#sequencer-node" aria-label="Permalink to &quot;Sequencer Node&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.block_time</span><span style="color:#BFF3C2;"> 500ms</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span></span></code></pre></div><h3 id="full-node" tabindex="-1">Full Node <a class="header-anchor" href="#full-node" aria-label="Permalink to &quot;Full Node&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.p2p.peers</span><span style="color:#BFF3C2;"> 12D3KooW...@sequencer.example.com:26656</span></span></code></pre></div><h3 id="lazy-aggregator" tabindex="-1">Lazy Aggregator <a class="header-anchor" href="#lazy-aggregator" aria-label="Permalink to &quot;Lazy Aggregator&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#94EEFF;">appd</span><span style="color:#BFF3C2;"> start</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.lazy_aggregator</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.node.lazy_block_time</span><span style="color:#BFF3C2;"> 5s</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.da.address</span><span style="color:#BFF3C2;"> http://localhost:7980</span><span style="color:#FFECB6;"> \\</span></span>\n<span class="line"><span style="color:#FFECB6;">  --evnode.signer.passphrase</span><span style="color:#BFF3C2;"> secret</span></span></code></pre></div>',28)])])}]]);export{s as __pageData,n as default};
